export default function handleMSPacket(data){const batchType=data.slice(0,4).toString();if(batchType!=="fdrs"){throw new Error("Invalid batch type")}const numberOfChannels=data.readUInt16LE(6);data=data.slice(8);const channelValues=[];for(let i=0;i<numberOfChannels;i++){channelValues.push(data.readUInt16LE(i*2)/655.35)}data=data.slice(numberOfChannels*2);const values={};const mapping={0:"LINE",1:"RETURN",2:"FXRETURN",3:"TALKBACK",4:"AUX",5:"FX",6:"SUB",7:"MAIN",8:"MONO",11:"MASTER"};const groupCount=data.readUInt8(0);for(let i=0;i<groupCount;i++){const dataOffset=1+i*6;const groupNumber=data.readUInt16LE(dataOffset);const offset=data.readUInt16LE(dataOffset+2);const count=data.readUInt16LE(dataOffset+4);let channelType=mapping[groupNumber];if(!channelType){console.warn("Unknown channel type",groupNumber);channelType=`unknown--${groupNumber}`}values[channelType]=channelValues.slice(offset,offset+count)}return values}